commands.cmd:
set --
[ -n '' ] && set -- "$@" --context ''
if [ -n '' ]; then
  kubectl get namespace '' "$@" >/dev/null || { echo "namespace not found or not readable" >&2; exit 1; }
  set -- "$@" -n ''
else
  set -- "$@" -A
fi
events=$(kubectl get events "$@" --field-selector=type=Warning -o json) || { echo "kubectl get events failed" >&2; exit 1; }
printf '%s' "$events" | jq -c '{
  results: [
    .items
    | map({
        reason: (.reason // "Unknown"),
        kind: (.involvedObject.kind // "Unknown"),
        namespace: (.metadata.namespace // ""),
        n: (.count // .series.count // 1)
      })
    | group_by([.reason, .kind, .namespace])[]
    | {
        reason: .[0].reason,
        kind: .[0].kind,
        namespace: .[0].namespace,
        count: (map(.n) | add)
      }
  ]
}' || { echo "jq failed" >&2; exit 1; }
